import{_ as t,o as a,c as r,a0 as s}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"Handle Password Reset Requests","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/handle-password-requests.md","filePath":"how-to/handle-password-requests.md"}'),o={name:"how-to/handle-password-requests.md"};function l(i,e,n,d,h,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="handle-password-reset-requests" tabindex="-1">Handle Password Reset Requests <a class="header-anchor" href="#handle-password-reset-requests" aria-label="Permalink to &quot;Handle Password Reset Requests&quot;">​</a></h1><p>The forgot-password flow in this tracker is admin-reviewed. Users submit a request, and an authorized admin decides whether to approve or reject it.</p><blockquote><p>Screenshot placeholder: admin-password-requests.png</p></blockquote><h2 id="open-the-request-list" tabindex="-1">Open the request list <a class="header-anchor" href="#open-the-request-list" aria-label="Permalink to &quot;Open the request list&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>Select <strong>Password requests</strong>.</li></ol><p>The list shows:</p><ul><li>what the person typed in <strong>Lookup</strong></li><li>the matched user, if one was found</li><li>the email address</li><li>the request message</li><li>the current status</li></ul><h2 id="review-a-request" tabindex="-1">Review a request <a class="header-anchor" href="#review-a-request" aria-label="Permalink to &quot;Review a request&quot;">​</a></h2><ol><li>Select <strong>Open</strong>.</li><li>Read the request details.</li><li>Add a <strong>Resolution note</strong> if your team wants one.</li></ol><p>From the detail page, you can:</p><ul><li><strong>Approve and email temporary password</strong></li><li><strong>Reject request</strong></li></ul><h2 id="if-you-approve" tabindex="-1">If you approve <a class="header-anchor" href="#if-you-approve" aria-label="Permalink to &quot;If you approve&quot;">​</a></h2><p>The system:</p><ul><li>creates a fresh temporary password</li><li>forces the user to change it at next login</li><li>emails the temporary password to the matched user&#39;s saved email address</li></ul><p>Approval only works when the request can be matched to a user account that has an email address.</p><h2 id="if-you-reject" tabindex="-1">If you reject <a class="header-anchor" href="#if-you-reject" aria-label="Permalink to &quot;If you reject&quot;">​</a></h2><p>The request is marked rejected. If the matched user has an email address, the system can send the rejection result there as well.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Approve only when you are comfortable that the request belongs to the real account owner.</li><li>Use the resolution note when the request was unusual or needed manual verification.</li><li>If the account itself needs cleanup, update the user profile after finishing the password request.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../getting-started/forgot-password.html">Reset a Forgotten Password</a></li><li><a href="./edit-user.html">Edit a User &amp; Reset Their Password</a></li><li><a href="./create-user.html">Create a User</a></li></ul>',21)])])}const m=t(o,[["render",l]]);export{c as __pageData,m as default};
